21	const BLOCK_SIZE = 3;
22	const BLOCK_PREMIUM = 60;
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	
25	const CURSED_RATE = 0.5;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	const HIGH_ENCHANTMENT_RATE = 0.3;
28	
29	const isCursed = (item: Item): boolean => item.cursed === true;
30	const isHighlyEnchanted = (item: Item): boolean =>
31	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
32	
33	const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
34	  { applies: isCursed, rate: CURSED_RATE },
35	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
36	];
37	
38	const groupByType = (items: Item[]): Map<string, Item[]> => {
39	  const groups = new Map<string, Item[]>();
40	  for (const item of items) {
41	    const group = groups.get(item.type) ?? [];
42	    group.push(item);
43	    groups.set(item.type, group);
44	  }
45	  return groups;
46	};
47	
48	const baseFor = (item: Item) => BASE_PREMIUM[item.type];
49	
50	const premiumForGroup = (type: string, group: Item[]) => {
51	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
52	    return BLOCK_PREMIUM;
53	  }
54	  return group.length * BASE_PREMIUM[type];
55	};
56	
57	const itemSurcharges = (item: Item) => {
58	  const base = baseFor(item);
59	  return SURCHARGE_RULES
60	    .filter((rule) => rule.applies(item))
61	    .reduce((sum, rule) => sum + base * rule.rate, 0);
62	};
63	
64	const policyBasePremium = (items: Item[]) =>
65	  [...groupByType(items)].reduce(
66	    (total, [type, group]) => total + premiumForGroup(type, group),
67	    0,
68	  );
69	
70	const sumItemSurcharges = (items: Item[]) =>
71	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
72	
73	const FIRST_INSURANCE_RATE = 0.1;
74	
75	const quote = (step: QuoteStep) => {
76	  const policyBase = policyBasePremium(step.items);
77	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
78	  const itemSurchargeTotal = sumItemSurcharges(step.items);
79	  const premium = policyBase + firstInsurance + itemSurchargeTotal;
80	  return { premium: Math.ceil(premium) + PROCESSING_FEE };
81	};
82	
83	export const run = (input: Scenario): unknown => ({
84	  results: input.steps.map(quote),
85	});
